{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/TrailingCommaOnDeclarationSiteRuleIssue1786Test.kt", "content": "package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.core.RuleProvider
import com.pinterest.ktlint.ruleset.standard.TrailingCommaOnDeclarationSiteRule.Companion.TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

/**
 * Tests for the issue where formatting enum class with member definition and missing trailing commas
 * causes rule violations on first run.
 *
 * See: https://github.com/pinterest/ktlint/issues/1786
 */
class TrailingCommaOnDeclarationSiteRuleIssue1786Test {
    private val trailingCommaOnDeclarationSiteRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                // WrappingRule must be loaded in order to run TrailingCommaOnDeclarationSiteRule
                RuleProvider { WrappingRule() },
                // Apply the IndentationRule always as additional rule, so that the formattedCode in the unit test looks
                // correct.
                RuleProvider { IndentationRule() },
                // Also include NoSemicolonsRule to verify the interaction between the rules
                RuleProvider { NoSemicolonsRule() },
            ),
        )

    @Test
    fun `Issue 1786 - Given an enum class with primary constructor and member definition then add trailing comma correctly`() {
        val code =
            """
            enum class TestEnum() {
                A,
                B;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            enum class TestEnum() {
                A,
                B,
                ;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasLintViolation(3, 6, "Missing trailing comma before \";\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue 1786 - Given an enum class with primary constructor with parameter and member definition then add trailing comma correctly`() {
        val code =
            """
            enum class TestEnum(val value: String) {
                A("a"),
                B("b");

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            enum class TestEnum(val value: String) {
                A("a"),
                B("b"),
                ;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasLintViolation(3, 11, "Missing trailing comma before \";\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue 1786 - Given an enum class with no primary constructor and member definition then add trailing comma correctly`() {
        val code =
            """
            enum class TestEnum {
                A,
                B;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            enum class TestEnum {
                A,
                B,
                ;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasLintViolation(3, 6, "Missing trailing comma before \";\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue 1786 - Given an enum class with function member then add trailing comma correctly`() {
        val code =
            """
            enum class TestEnum {
                A,
                B;

                fun doSomething() {}
            }
            """.trimIndent()
        val formattedCode =
            """
            enum class TestEnum {
                A,
                B,
                ;

                fun doSomething() {}
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasLintViolation(3, 6, "Missing trailing comma before \";\"")
            .isFormattedAs(formattedCode)
    }
}
